import React, {useEffect, useState} from 'react';
import StormShieldMap from '../components/StormShieldMap';
import { getSheltersApi, getApprovedReportsApi, getActiveAlertsApi } from '../api/apiServices';
import { Link } from 'react-router-dom';

const Dashboard = () => {
  const [shelters, setShelters] = useState([]);
  const [reports, setReports] = useState([]);
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    getSheltersApi().then(res => setShelters(res.data)).catch(console.error);
    getApprovedReportsApi().then(res => setReports(res.data)).catch(console.error);
    getActiveAlertsApi().then(res => setAlerts(res.data)).catch(console.error);
  }, []);

  return (
    <div className="container">
      <div style={{display:'flex', justifyContent:'space-between', marginBottom:'20px'}}>
        <h2>Bảng điều khiển StormShield</h2>
        <div>
          <Link to="/shelters" className="btn btn-outline" style={{marginRight:'10px'}}>Tìm điểm trú ẩn</Link>
          <Link to="/report-hazard" className="btn btn-danger" style={{marginRight:'10px'}}>Báo nguy hiểm</Link>
          <Link to="/request-support" className="btn">Yêu cầu hỗ trợ</Link>
        </div>
      </div>
      
      {alerts.length > 0 && (
        <div style={{background: 'var(--danger)', color: 'white', padding: '15px', borderRadius: '12px', marginBottom: '20px'}}>
          <strong>CẢNH BÁO MỚI:</strong> {alerts[0].title}
        </div>
      )}

      <StormShieldMap shelters={shelters} reports={reports} alerts={alerts} />
    </div>
  );
};
export default Dashboard;
